const baseUrl = 'https://bilig.proompteng.ai';

return [
  {
    json: {
      requestId: 'deal-1042-renewal',
      account: 'Northstar Systems',
      owner: 'revops',
      sheetName: 'Inputs',
      address: 'B3',
      value: 0.4,
      minExpectedArr: 90000,
      maxTargetGap: 6000,
      baseUrl
    }
  },
  {
    json: {
      requestId: 'deal-1188-expansion',
      account: 'Harbor Analytics',
      owner: 'finance',
      sheetName: 'Inputs',
      address: 'B4',
      value: 6500,
      minExpectedArr: 90000,
      maxTargetGap: 6000,
      baseUrl
    }
  },
  {
    json: {
      requestId: 'deal-1211-risk-review',
      account: 'Cedar Works',
      owner: 'sales-ops',
      sheetName: 'Inputs',
      address: 'B3',
      value: 0.22,
      minExpectedArr: 90000,
      maxTargetGap: 6000,
      baseUrl
    }
  }
];

return $input.all().map((item) => {
  const row = item.json;
  const value = Number(row.value);

  if (!Number.isFinite(value)) {
    throw new Error(`Forecast value must be numeric for ${row.requestId}`);
  }

  if (!['B2', 'B3', 'B4', 'B5'].includes(row.address)) {
    throw new Error(`Unsupported forecast input cell ${row.address} for ${row.requestId}`);
  }

  return {
    json: {
      ...row,
      value,
      minExpectedArr: Number(row.minExpectedArr),
      maxTargetGap: Number(row.maxTargetGap),
      normalizedAt: new Date().toISOString()
    }
  };
});

return $input.all().map((item) => {
  const row = item.json;

  return {
    json: {
      ...row,
      biligPayload: {
        sheetName: row.sheetName,
        address: row.address,
        value: row.value
      }
    }
  };
});

const scenarios = $('Build Bilig request').all();

return $input.all().map((item, index) => {
  const proof = item.json;
  const scenario = scenarios[index]?.json;

  if (!scenario) {
    throw new Error(`Missing source scenario for Bilig response ${index}`);
  }

  if (proof.verified !== true) {
    throw new Error(`Bilig did not verify ${scenario.requestId}: ${JSON.stringify(proof)}`);
  }

  if (!proof.checks?.formulasPersisted || !proof.checks?.restoredMatchesAfter || !proof.checks?.computedOutputChanged) {
    throw new Error(`Formula checks failed for ${scenario.requestId}: ${JSON.stringify(proof.checks)}`);
  }

  return {
    json: {
      ...scenario,
      proof,
      editedCell: proof.editedCell,
      beforeExpectedArr: proof.before.expectedArr,
      afterExpectedArr: proof.after.expectedArr,
      targetGap: proof.after.targetGap,
      formulaChecks: proof.checks
    }
  };
});

return $input.all().map((item) => {
  const row = item.json;
  const expectedArrOk = row.afterExpectedArr >= row.minExpectedArr;
  const targetGapOk = Math.abs(row.targetGap) <= row.maxTargetGap;
  const decision = expectedArrOk && targetGapOk ? 'approve' : 'review';

  return {
    json: {
      ...row,
      expectedArrOk,
      targetGapOk,
      decision,
      decisionReason: decision === 'approve'
        ? 'Fresh formula output is within policy.'
        : 'Fresh formula output needs owner review before the workflow continues.'
    }
  };
});

return $input.all().map((item) => {
  const row = item.json;

  return {
    json: {
      status: 'approved',
      requestId: row.requestId,
      account: row.account,
      owner: row.owner,
      editedCell: row.editedCell,
      expectedArr: row.afterExpectedArr,
      targetGap: row.targetGap,
      evidence: {
        verified: row.proof.verified,
        formulasPersisted: row.formulaChecks.formulasPersisted,
        restoredMatchesAfter: row.formulaChecks.restoredMatchesAfter,
        computedOutputChanged: row.formulaChecks.computedOutputChanged
      }
    }
  };
});

return $input.all().map((item) => {
  const row = item.json;

  return {
    json: {
      status: 'needs_review',
      requestId: row.requestId,
      account: row.account,
      owner: row.owner,
      editedCell: row.editedCell,
      expectedArr: row.afterExpectedArr,
      targetGap: row.targetGap,
      failedPolicy: {
        expectedArrOk: row.expectedArrOk,
        targetGapOk: row.targetGapOk
      },
      reviewerNote: `${row.account} needs review because the freshly recalculated workbook output missed policy.`
    }
  };
});

return $input.all().map((item) => {
  const row = item.json;

  return {
    json: {
      ...row,
      auditSummary: `${row.status}: ${row.account} ${row.editedCell} expected ARR ${row.expectedArr} target gap ${row.targetGap}`,
      nextStep: row.status === 'approved'
        ? 'Send this record to CRM, Slack, or a quote approval system.'
        : 'Route this record to the deal owner before the workflow continues.',
      github: 'https://github.com/proompteng/bilig',
      package: '@bilig/workpaper'
    }
  };
});
